sql:
SELECT song_name
FROM songs
WHERE year = 2020;

SELECT genre_name
FROM genres
WHERE genre_id = (SELECT MAX(genre_id) FROM genres);

SELECT genre_id, COUNT(*) 
FROM songs 
GROUP BY genre_id;

SELECT album_name, release_date
FROM albums
ORDER BY release_date DESC;

SELECT song_name, genre_name
FROM songs
JOIN genres ON songs.genre_id = genres.genre_id;

SELECT COUNT(DISTINCT song_id) AS number_of_listened_songs
FROM user_engagement
WHERE listen_count > 10;

external_knowledge:
- 'popular tunes' refers to songs with high listening times; 
- 'premium listeners' are users with a 'premium' subscription plan; 
- 'total time they've been spun' means the aggregate duration of the song's plays by these users.
